                          selectedContainer &&
                          requestLifecycleAction("start", selectedContainer)
                        }
                        size="icon"
                        title={
                          selectedCanStart
                            ? "启动容器"
                            : "容器未运行或正在重启"
                        }
                        type="button"
                        variant="primary"
                      >
                        {selectedActionBusy ? (
                          <RefreshCw className="h-3.5 w-3.5 animate-spin" />
                        ) : (
                          <Play className="h-3.5 w-3.5" />
                        )}
