  );
}

function SummaryMetric({ label, value }: { label: string; value: number }) {
  return (
    <div className="border-r border-[var(--border-subtle)] px-3 py-2 last:border-r-0">
      <div className="font-mono text-lg font-semibold leading-6 text-zinc-950 dark:text-zinc-50">
        {value}
      </div>
      <div className="text-[11px] text-zinc-500 dark:text-zinc-400">
        {label}
      </div>
    </div>
  );
}

function StateMessage({
  children,
  tone = "muted",
}: {
  children: string;
  tone?: "danger" | "muted";
}) {
  return (
    <div
      className={cn(
        "flex min-h-32 items-center justify-center rounded-2xl border px-4 py-8 text-center text-sm",
        tone === "danger"
          ? "border-red-500/20 bg-red-500/10 text-red-700 dark:text-red-200"
          : "border-dashed border-[var(--border-subtle)] text-zinc-500 dark:text-zinc-400",
      )}
    >
      {children}
    </div>
  );
}

function resolveHostContainerSelection(
  containers: DockerContainerSummary[],
  groupMode: HostContainerGroupMode,
  current: HostContainerSelection,
  initialContainerId?: string,
): HostContainerSelection {
  const hasContainer = (containerId: string) =>
    containers.some((container) => container.id === containerId);

  if (initialContainerId && hasContainer(initialContainerId)) {
    return { kind: "container", containerId: initialContainerId };
  }
  if (current?.kind === "container" && hasContainer(current.containerId)) {
    return current;
  }

  if (groupMode === "compose") {
    const composeView = buildComposeProjectViews(containers);
    if (
      current?.kind === "project" &&
      composeView.projects.some((project) => project.id === current.projectId)
    ) {
      return current;
    }
    if (composeView.projects[0]) {
      return { kind: "project", projectId: composeView.projects[0].id };
    }
  }

  return containers[0]
    ? { kind: "container", containerId: containers[0].id }
    : null;
}

function formatHostIdentity(host: Machine) {
  const endpoint = host.host
    ? `${host.username ? `${host.username}@` : ""}${host.host}${
        host.port ? `:${host.port}` : ""
      }`
    : host.description;
  return `${endpoint} · ${host.production ? "production" : "workspace"} · SSH`;
}

function errorMessage(error: unknown) {
  if (error instanceof Error) {
    return error.message;
  }
  return String(error);
}

function lifecycleActionText(action: HostContainerLifecycleAction) {
  switch (action) {
    case "start":
      return "启动";
    case "stop":
      return "停止";
    case "restart":
      return "重启";
    case "remove":
      return "删除";
    default:
      return "处理";
  }
}

function isTypingTarget(target: EventTarget | null) {
  if (!(target instanceof HTMLElement)) {
    return false;
  }
  const tagName = target.tagName.toLowerCase();
  return (
    tagName === "input" || tagName === "textarea" || target.isContentEditable
  );
}

/**
 * Host container row lifecycle actions menu.
 *
 * @author kongweiguang
 */

import { useEffect, useRef, useState } from "react";
import { createPortal } from "react-dom";
import {
  Activity,
  Info,
  MoreHorizontal,
  Play,
  RotateCw,
  Square,
  Trash2,
} from "lucide-react";
import { cn } from "../../../lib/cn";
import {
  canRunHostContainerLifecycleAction,
  hostContainerLifecycleDisabledReason,
  type HostContainerInspectorTab,
  type HostContainerLifecycleAction,
  type HostContainerMetadata,
} from "./hostContainerDialogModel";

interface HostContainerActionsMenuProps {
  container: HostContainerMetadata;
  onAction: (
    action: HostContainerLifecycleAction,
    container: HostContainerMetadata,
  ) => void;
  onInspectAction: (
    tab: HostContainerInspectorTab,
    container: HostContainerMetadata,
  ) => void;
  onSelectContainer: (containerId: string) => void;
}

type MenuPosition = {
  left: number;
  top: number;
};

const lifecycleItems: Array<{
  action: HostContainerLifecycleAction;
  danger?: boolean;
  icon: typeof Play;
  label: string;
}> = [
  { action: "start", icon: Play, label: "启动" },
  { action: "stop", danger: true, icon: Square, label: "停止" },
  { action: "restart", icon: RotateCw, label: "重启" },
  { action: "remove", danger: true, icon: Trash2, label: "删除" },
];

const inspectorItems: Array<{
  icon: typeof Info;
  label: string;
  tab: HostContainerInspectorTab;
}> = [
  { icon: Info, label: "详情", tab: "details" },
  { icon: Activity, label: "监控", tab: "stats" },
];

export function HostContainerActionsMenu({
  container,
  onAction,
  onInspectAction,
  onSelectContainer,
}: HostContainerActionsMenuProps) {
  const [position, setPosition] = useState<MenuPosition | null>(null);
  const buttonRef = useRef<HTMLButtonElement>(null);
  const menuRef = useRef<HTMLDivElement>(null);
  const open = Boolean(position);

  useEffect(() => {
    if (!open) {
      return undefined;
    }

    const close = () => setPosition(null);
    const closeOnPointerDown = (event: PointerEvent) => {
      const target = event.target;
      if (!(target instanceof Node)) {
        return;
      }
      if (
        menuRef.current?.contains(target) ||
        buttonRef.current?.contains(target)
      ) {
        return;
      }
      close();
    };
    const closeOnKeyDown = (event: KeyboardEvent) => {
      if (event.key === "Escape") {
        close();
      }
    };

    window.addEventListener("pointerdown", closeOnPointerDown, true);
    window.addEventListener("keydown", closeOnKeyDown, true);
    window.addEventListener("resize", close);
    window.addEventListener("scroll", close, true);
    return () => {
      window.removeEventListener("pointerdown", closeOnPointerDown, true);
      window.removeEventListener("keydown", closeOnKeyDown, true);
      window.removeEventListener("resize", close);
      window.removeEventListener("scroll", close, true);
    };
  }, [open]);

  const openMenu = () => {
    const rect = buttonRef.current?.getBoundingClientRect();
    if (!rect) {
      return;
    }
    const menuWidth = 176;
    setPosition({
      left: Math.max(
        12,
        Math.min(rect.right - menuWidth, window.innerWidth - menuWidth - 12),
      ),
      top: Math.max(12, Math.min(rect.bottom + 6, window.innerHeight - 280)),
    });
  };

  const selectAction = (action: HostContainerLifecycleAction) => {
    onSelectContainer(container.id);
    setPosition(null);
    onAction(action, container);
  };
  const selectInspectAction = (tab: HostContainerInspectorTab) => {
    onSelectContainer(container.id);
    setPosition(null);
    onInspectAction(tab, container);
  };
  return (
    <>
      <button
        aria-expanded={open}
        aria-haspopup="menu"
        aria-label={`更多容器操作 ${container.name}`}
        className="kerminal-pressable kerminal-focus-ring inline-flex h-8 w-8 items-center justify-center rounded-lg text-zinc-500 transition-colors hover:bg-[var(--surface-hover)] hover:text-zinc-950 dark:text-zinc-400 dark:hover:text-zinc-50"
        onClick={(event) => {
          event.stopPropagation();
          if (open) {
            setPosition(null);
            return;
          }
          openMenu();
        }}
        ref={buttonRef}
        title="更多容器操作"
        type="button"
      >
        <MoreHorizontal className="h-4 w-4" />
      </button>
      {position
        ? createPortal(
            <div
              className="kerminal-context-menu kerminal-floating-enter fixed z-[1001] w-44"
              onClick={(event) => event.stopPropagation()}
              ref={menuRef}
              role="menu"
              style={{
                left: position.left,
                top: position.top,
              }}
            >
              <div className="kerminal-context-menu-group">
                {inspectorItems.map((item) => {
                  const Icon = item.icon;
                  return (
                    <button
                      className="kerminal-context-menu-item"
                      key={item.tab}
                      onClick={() => selectInspectAction(item.tab)}
                      role="menuitem"
                      type="button"
                    >
                      <span className="kerminal-context-menu-icon">
                        <Icon />
                      </span>
                      <span className="kerminal-context-menu-label">
                        {item.label}
                      </span>
                    </button>
                  );
                })}
              </div>
              <div className="kerminal-context-menu-group">
                {lifecycleItems.map((item) => {
                  const Icon = item.icon;
                  const disabled = !canRunHostContainerLifecycleAction(
                    container,
                    item.action,
                  );
                  const disabledReason = hostContainerLifecycleDisabledReason(
                    container,
                    item.action,
                  );
                  return (
                    <button
                      className={cn(
                        "kerminal-context-menu-item",
                        item.danger && "kerminal-context-menu-item--danger",
                      )}
                      disabled={disabled}
                      key={item.action}
                      onClick={() => selectAction(item.action)}
                      role="menuitem"
                      title={disabledReason}
                      type="button"
                    >
                      <span className="kerminal-context-menu-icon">
                        <Icon />
                      </span>
                      <span className="kerminal-context-menu-label">
                        {item.label}
                      </span>
                    </button>
                  );
                })}
              </div>
            </div>,
            document.body,
          )
        : null}
    </>
  );
}

