          {metadataParts.map((part, index) => (
            <span
              className={cn(index === 0 && "font-mono", "min-w-0 truncate")}
              key={`${container.id}:${part}`}
            >
              {part}
            </span>
          ))}
        </div>
      </div>
      <div className="grid w-[8.75rem] shrink-0 grid-cols-4 items-center justify-end gap-1 self-center">
        {canEnter ? (
          <Button
            aria-label={`进入容器 ${container.name}`}
            className={cn(
              rowIconButtonClassName,
              selected && "text-white hover:text-white",
            )}
            onClick={(event) => {
              event.stopPropagation();
              enterContainer();
            }}
            size="icon"
            title="进入容器终端"
            type="button"
            variant={selected ? "primary" : "secondary"}
          >
            <Terminal className="h-4 w-4" />
          </Button>
        ) : (
          <Button
            aria-label={`启动容器 ${container.name}`}
            className={cn(
              rowIconButtonClassName,
              selected && canStart && "text-white hover:text-white",
            )}
            disabled={!canStart}
            onClick={(event) => {
              event.stopPropagation();
              selectContainer();
              onLifecycleAction("start", container);
            }}
            size="icon"
            title={canStart ? "启动容器" : "容器正在重启"}
            type="button"
            variant={selected && canStart ? "primary" : "secondary"}
          >
            <Play className="h-4 w-4" />
          </Button>
        )}
        <Button
          aria-label={`查看容器 ${container.name} 日志`}
          className={rowIconButtonClassName}
          onClick={(event) => {
            event.stopPropagation();
            selectContainer();
            onOpenLogs(container);
          }}
          size="icon"
          title="打开实时日志终端"
          type="button"
          variant="ghost"
        >
          <ScrollText className="h-4 w-4" />
        </Button>
        <Button
          aria-label={`固定容器 ${container.name} 到侧栏`}
          className={rowIconButtonClassName}
          disabled={pinning}
          onClick={(event) => {
            event.stopPropagation();
            selectContainer();
            onPinContainer(container);
          }}
          size="icon"
          title="固定到侧栏"
          type="button"
          variant="ghost"
        >
          <Pin className="h-4 w-4" />
        </Button>
        <HostContainerActionsMenu
          container={container}
          onAction={onLifecycleAction}
          onInspectAction={onInspectAction}
          onSelectContainer={onSelectContainer}
        />
      </div>
    </div>
  );
}

function areSetsEqual(left: Set<string>, right: Set<string>) {
  if (left.size !== right.size) {
    return false;
  }
  for (const value of left) {
    if (!right.has(value)) {
      return false;
    }
  }
  return true;
}

/**
 * Compose-aware host container project view model.
 *
 * @author kongweiguang
 */

import type {
  DockerContainerStatus,
  DockerContainerSummary,
} from "../../../lib/dockerApi";
import type { ContainerRuntime } from "../../../lib/targetModel";

export type ComposeRuntimeFamily = "docker" | "podman" | "unknown";

export interface DockerComposeContainerMetadata {
  project?: string | null;
  service?: string | null;
  workingDir?: string | null;
  working_dir?: string | null;
  configFiles?: string[] | null;
  config_files?: string[] | null;
  configPaths?: string[] | null;
  config_paths?: string[] | null;
  containerNumber?: string | null;
  container_number?: string | null;
  oneoff?: boolean | null;
  runtimeFamily?: string | null;
  runtime_family?: string | null;
}

export interface LegacyComposeContainerFields {
  composeProject?: string;
  composeService?: string;
  labels?: Record<string, string>;
  project?: string;
}

export type ComposeAwareContainerSummary =
  DockerContainerSummary & LegacyComposeContainerFields;

export type ComposeProjectContainerSummary = Omit<
  DockerContainerSummary,
  "compose"
> &
  LegacyComposeContainerFields & {
    compose?: DockerComposeContainerMetadata | null;
  };

export interface ComposeConfigPathResolution {
  configFiles: string[];
  configPaths: string[];
  warnings: string[];
  workingDir?: string;
}

export interface ComposeContainerView {
  container: ComposeProjectContainerSummary;
  containerNumber?: string;
  id: string;
  image: string;
  name: string;
  oneoff: boolean;
  ports: string[];
  searchText: string;
  service: string;
  status: DockerContainerStatus;
  statusText: string;
}

export interface ComposeServiceView {
  containers: ComposeContainerView[];
  errorCount: number;
  id: string;
  runningCount: number;
  service: string;
  stoppedCount: number;
  totalCount: number;
}

export interface ComposeProjectView {
  configFiles: string[];
  configPaths: string[];
  containers: ComposeContainerView[];
  errorCount: number;
  id: string;
  project: string;
  runningCount: number;
  runtime: ContainerRuntime;
  runtimeFamily: ComposeRuntimeFamily;
  searchText: string;
  services: ComposeServiceView[];
  stoppedCount: number;
  totalCount: number;
  warningCount: number;
  warnings: string[];
  workingDir?: string;
}

export interface ComposeStandaloneContainerView {
  container: ComposeProjectContainerSummary;
  id: string;
  image: string;
  name: string;
  ports: string[];
  runtime: ContainerRuntime;
  searchText: string;
  status: DockerContainerStatus;
  statusText: string;
}

export interface ComposeProjectViews {
  errorCount: number;
  projects: ComposeProjectView[];
  runningCount: number;
  standaloneContainers: ComposeStandaloneContainerView[];
  stoppedCount: number;
  totalCount: number;
  warningCount: number;
  warnings: string[];
}

const dockerComposeLabels = {
  configFiles: "com.docker.compose.project.config_files",
  containerNumber: "com.docker.compose.container-number",
  oneoff: "com.docker.compose.oneoff",
  project: "com.docker.compose.project",
  service: "com.docker.compose.service",
  workingDir: "com.docker.compose.project.working_dir",
} as const;

const podmanComposeLabels = {
  configFiles: "io.podman.compose.project.config_files",
  project: "io.podman.compose.project",
  service: "io.podman.compose.service",
  workingDir: "io.podman.compose.project.working_dir",
} as const;

const statusSortOrder: Record<DockerContainerStatus, number> = {
  running: 0,
  restarting: 1,
  paused: 2,
  created: 3,
  exited: 4,
  dead: 5,
  unknown: 6,
};

export function buildComposeProjectViews(
  containers: ComposeProjectContainerSummary[],
): ComposeProjectViews {
  const projectContainers = new Map<string, ComposeProjectContainerSummary[]>();
  const standaloneContainers: ComposeProjectContainerSummary[] = [];

  for (const container of containers) {
    const project = readContainerComposeProject(container);
    if (!project) {
      standaloneContainers.push(container);
      continue;
    }
    const key = composeProjectKey(container, project);
    projectContainers.set(key, [
      ...(projectContainers.get(key) ?? []),
      container,
    ]);
  }

  const projects = [...projectContainers.values()]
    .map(buildComposeProjectView)
    .sort(compareComposeProjects);
  const standaloneViews = sortContainers(standaloneContainers).map(
    buildStandaloneContainerView,
  );
  const stats = containerStats(containers);
  const warnings = projects.flatMap((project) =>
    project.warnings.map((warning) => `${project.project}: ${warning}`),
  );

  return {
    errorCount: stats.errorCount,
    projects,
    runningCount: stats.runningCount,
    standaloneContainers: standaloneViews,
    stoppedCount: stats.stoppedCount,
    totalCount: stats.totalCount,
    warningCount: warnings.length,
    warnings,
  };
}

export function readContainerComposeProject(
  container: ComposeProjectContainerSummary,
) {
  return (
    trimText(container.compose?.project) ||
    trimText(container.project) ||
    trimText(container.composeProject) ||
    readLabel(container, dockerComposeLabels.project) ||
    readLabel(container, podmanComposeLabels.project) ||
    ""
  );
}

export function readContainerComposeService(
  container: ComposeProjectContainerSummary,
) {
  return (
    trimText(container.compose?.service) ||
    trimText(container.composeService) ||
    readLabel(container, dockerComposeLabels.service) ||
    readLabel(container, podmanComposeLabels.service) ||
    ""
  );
}

export function readContainerComposeConfigPaths(
  container: ComposeProjectContainerSummary,
) {
  return readContainerComposeConfigPathResolution(container).configPaths;
}

export function readContainerComposeConfigPathResolution(
  container: ComposeProjectContainerSummary,
): ComposeConfigPathResolution {
  return resolveComposeConfigPaths({
    configFiles: readContainerComposeConfigFiles(container),
    configPaths: firstNonEmptyStringList([
      readStringList(container.compose?.configPaths),
      readStringList(container.compose?.config_paths),
    ]),
    workingDir: readContainerComposeWorkingDir(container),
  });
}

export function resolveComposeConfigPaths({
  configFiles = [],
  configPaths = [],
  workingDir,
}: {
  configFiles?: string[];
  configPaths?: string[];
  workingDir?: string;
}): ComposeConfigPathResolution {
  const normalizedWorkingDir = trimText(workingDir);
  const normalizedConfigFiles = uniqueStrings(configFiles);
  const normalizedConfigPaths = uniqueStrings(configPaths);
  const warnings: string[] = [];

  if (normalizedConfigPaths.length > 0) {
    return {
      configFiles: normalizedConfigFiles,
      configPaths: normalizedConfigPaths,
      warnings,
      ...(normalizedWorkingDir ? { workingDir: normalizedWorkingDir } : {}),
    };
  }

  if (normalizedConfigFiles.length === 0) {
    warnings.push("未发现 Compose YAML 路径");
    return {
      configFiles: [],
      configPaths: [],
      warnings,
      ...(normalizedWorkingDir ? { workingDir: normalizedWorkingDir } : {}),
    };
  }

  const unresolvedRelativePaths = normalizedConfigFiles.some(
    (path) => !isAbsolutePath(path),
  );
  if (unresolvedRelativePaths && !normalizedWorkingDir) {
    warnings.push("Compose YAML 包含相对路径但缺少 workingDir");
  }

  return {
    configFiles: normalizedConfigFiles,
    configPaths: normalizedConfigFiles.map((path) =>
      resolveComposeConfigPath(path, normalizedWorkingDir),
    ),
    warnings,
    ...(normalizedWorkingDir ? { workingDir: normalizedWorkingDir } : {}),
  };
}

export function composeProjectMatchesQuery(
  project: ComposeProjectView,
  query: string,
) {
  const normalizedQuery = normalizeSearch(query);
  return !normalizedQuery || project.searchText.includes(normalizedQuery);
}

export function composeStandaloneContainerMatchesQuery(
  container: ComposeStandaloneContainerView,
  query: string,
) {
  const normalizedQuery = normalizeSearch(query);
  return !normalizedQuery || container.searchText.includes(normalizedQuery);
}

function buildComposeProjectView(
  containers: ComposeProjectContainerSummary[],
): ComposeProjectView {
  const sortedContainers = sortContainers(containers);
  const firstContainer = sortedContainers[0]!;
  const project = readContainerComposeProject(firstContainer);
  const runtimeFamily = readContainerComposeRuntimeFamily(firstContainer);
  const config = resolveProjectConfig(sortedContainers);
  const containerViews = sortedContainers.map((container) =>
    buildComposeContainerView(container),
  );
  const services = buildComposeServiceViews(containerViews, project);
  const stats = containerStats(sortedContainers);
  const searchText = buildSearchText([
    project,
    firstContainer.runtime,
    runtimeFamily,
    config.workingDir,
    ...config.configPaths,
    ...config.configFiles,
    ...containerViews.map((container) => container.searchText),
  ]);

  return {
    configFiles: config.configFiles,
    configPaths: config.configPaths,
    containers: containerViews,
    errorCount: stats.errorCount,
    id: composeProjectId(firstContainer, project),
    project,
    runningCount: stats.runningCount,
    runtime: firstContainer.runtime,
    runtimeFamily,
    searchText,
    services,
    stoppedCount: stats.stoppedCount,
    totalCount: stats.totalCount,
    warningCount: config.warnings.length,
    warnings: config.warnings,
    ...(config.workingDir ? { workingDir: config.workingDir } : {}),
  };
}

function buildComposeContainerView(
  container: ComposeProjectContainerSummary,
): ComposeContainerView {
  const service = readContainerComposeService(container) || "other";
  return {
    container,
    ...(readContainerComposeContainerNumber(container)
      ? { containerNumber: readContainerComposeContainerNumber(container) }
      : {}),
    id: container.id,
    image: container.image,
    name: container.name,
    oneoff: readContainerComposeOneoff(container),
    ports: container.ports,
    searchText: buildContainerSearchText(container, [
      readContainerComposeProject(container),
      service,
      ...readContainerComposeConfigPaths(container),
    ]),
    service,
    status: container.status,
    statusText: container.statusText,
  };
}

function buildComposeServiceViews(
  containers: ComposeContainerView[],
  project: string,
): ComposeServiceView[] {
  const serviceContainers = new Map<string, ComposeContainerView[]>();
  for (const container of containers) {
    serviceContainers.set(container.service, [
      ...(serviceContainers.get(container.service) ?? []),
      container,
    ]);
  }

  return [...serviceContainers.entries()]
    .map(([service, serviceContainerViews]) => {
      const stats = containerStats(
        serviceContainerViews.map((container) => container.container),
      );
      return {
        containers: serviceContainerViews,
        errorCount: stats.errorCount,
        id: `${project}:service:${service}`,
        runningCount: stats.runningCount,
        service,
        stoppedCount: stats.stoppedCount,
        totalCount: stats.totalCount,
      };
    })
    .sort(compareComposeServices);
}

function buildStandaloneContainerView(
  container: ComposeProjectContainerSummary,
): ComposeStandaloneContainerView {
  return {
    container,
    id: container.id,
    image: container.image,
    name: container.name,
    ports: container.ports,
    runtime: container.runtime,
    searchText: buildContainerSearchText(container),
    status: container.status,
    statusText: container.statusText,
  };
}

function resolveProjectConfig(
  containers: ComposeProjectContainerSummary[],
): ComposeConfigPathResolution {
  const workingDirs = uniqueStrings(
    containers.map(readContainerComposeWorkingDir),
  );
  const resolutions = containers.map(readContainerComposeConfigPathResolution);
  const configFiles = firstNonEmptyStringList(
    resolutions.map((resolution) => resolution.configFiles),
  );
  const configPaths = firstNonEmptyStringList(
    resolutions.map((resolution) => resolution.configPaths),
  );
  const warnings: string[] = [];
  const pathSets = uniqueStrings(
    resolutions
      .map((resolution) => resolution.configPaths.join("\n"))
      .filter(Boolean),
  );

  if (workingDirs.length > 1) {
    warnings.push("同一 Compose 项目存在多个 workingDir");
  }
  if (pathSets.length > 1) {
    warnings.push("同一 Compose 项目存在多组 Compose YAML 路径");
  }
  if (configPaths.length === 0) {
    warnings.push("未发现 Compose YAML 路径");
  }
  if (
    configFiles.some((path) => !isAbsolutePath(path)) &&
    workingDirs.length === 0
  ) {
    warnings.push("Compose YAML 包含相对路径但缺少 workingDir");
  }

  return {
    configFiles,
    configPaths,
    warnings: uniqueStrings(warnings),
    ...(workingDirs[0] ? { workingDir: workingDirs[0] } : {}),
  };
}

function readContainerComposeWorkingDir(
  container: ComposeProjectContainerSummary,
) {
  return (
    trimText(container.compose?.workingDir) ||
    trimText(container.compose?.working_dir) ||
    readLabel(container, dockerComposeLabels.workingDir) ||
    readLabel(container, podmanComposeLabels.workingDir) ||
    ""
  );
}

function readContainerComposeConfigFiles(
  container: ComposeProjectContainerSummary,
) {
  return firstNonEmptyStringList([
    readStringList(container.compose?.configFiles),
    readStringList(container.compose?.config_files),
    splitComposeConfigFiles(
      readLabel(container, dockerComposeLabels.configFiles),
    ),
    splitComposeConfigFiles(
      readLabel(container, podmanComposeLabels.configFiles),
    ),
  ]);
}

function readContainerComposeContainerNumber(
  container: ComposeProjectContainerSummary,
) {
  return (
    trimText(container.compose?.containerNumber) ||
    trimText(container.compose?.container_number) ||
    readLabel(container, dockerComposeLabels.containerNumber) ||
    ""
  );
}

function readContainerComposeOneoff(container: ComposeProjectContainerSummary) {
  const oneoff = container.compose?.oneoff;
  if (typeof oneoff === "boolean") {
    return oneoff;
  }
  return (
    readLabel(container, dockerComposeLabels.oneoff).toLowerCase() === "true"
  );
}

function readContainerComposeRuntimeFamily(
  container: ComposeProjectContainerSummary,
): ComposeRuntimeFamily {
  const runtimeFamily = (
    trimText(container.compose?.runtimeFamily) ||
    trimText(container.compose?.runtime_family)
  ).toLowerCase();
  if (runtimeFamily.includes("podman")) {
    return "podman";
  }
  if (runtimeFamily.includes("docker")) {
    return "docker";
  }
  if (readLabel(container, podmanComposeLabels.project)) {
    return "podman";
  }
  if (readLabel(container, dockerComposeLabels.project)) {
    return "docker";
  }
  return container.runtime === "podman" ? "podman" : "docker";
}

function composeProjectKey(
  container: ComposeProjectContainerSummary,
  project: string,
) {
  return `${container.runtime}:${readContainerComposeRuntimeFamily(
    container,
  )}:${project}`;
}

function composeProjectId(
  container: ComposeProjectContainerSummary,
  project: string,
) {
  return `compose:${composeProjectKey(container, project)}`;
}

function containerStats(containers: ComposeProjectContainerSummary[]) {
  const runningCount = containers.filter(
    (container) => container.status === "running",
  ).length;
  const errorCount = containers.filter((container) =>
    isContainerErrorStatus(container.status),
  ).length;
  return {
    errorCount,
    runningCount,
    stoppedCount: containers.length - runningCount,
    totalCount: containers.length,
  };
}

function isContainerErrorStatus(status: DockerContainerStatus) {
  return status === "dead";
}

function sortContainers(containers: ComposeProjectContainerSummary[]) {
  return [...containers].sort(
    (left, right) =>
      statusSortOrder[left.status] - statusSortOrder[right.status] ||
      readContainerComposeProject(left).localeCompare(
        readContainerComposeProject(right),
      ) ||
      readContainerComposeService(left).localeCompare(
        readContainerComposeService(right),
      ) ||
      left.name.localeCompare(right.name),
  );
}

function compareComposeProjects(
  left: ComposeProjectView,
  right: ComposeProjectView,
) {
  return (
    right.runningCount - left.runningCount ||
    left.project.localeCompare(right.project)
  );
}

function compareComposeServices(
  left: ComposeServiceView,
  right: ComposeServiceView,
) {
  if (left.service === "other" || right.service === "other") {
    return left.service === "other" ? 1 : -1;
  }
  return (
    right.runningCount - left.runningCount ||
    left.service.localeCompare(right.service)
  );
}

function buildContainerSearchText(
  container: ComposeProjectContainerSummary,
  extraParts: Array<string | undefined> = [],
) {
  return buildSearchText([
    container.name,
    container.image,
    container.shortId,
    container.id,
    container.statusText,
    container.state,
    container.runtime,
    ...container.ports,
    ...extraParts,
  ]);
}

function buildSearchText(parts: Array<string | undefined>) {
  return parts.filter(Boolean).join(" ").toLowerCase();
}

function normalizeSearch(query: string) {
  return query.trim().toLowerCase();
}

function readLabel(container: ComposeProjectContainerSummary, key: string) {
  return trimText(container.labels?.[key]);
}

function readStringList(
  value: Array<string | null | undefined> | null | undefined,
) {
  return uniqueStrings(value ?? []);
}

function splitComposeConfigFiles(value: string) {
  if (!value) {
    return [];
  }
  const separator = value.includes(",") ? "," : ";";
  return uniqueStrings(value.split(separator));
}

function firstNonEmptyStringList(lists: string[][]) {
  return lists.find((list) => list.length > 0) ?? [];
}

function uniqueStrings(values: Array<string | null | undefined>) {
  const seen = new Set<string>();
  const result: string[] = [];
  for (const value of values) {
    const normalized = trimText(value);
    if (!normalized || seen.has(normalized)) {
      continue;
    }
    seen.add(normalized);
    result.push(normalized);
  }
  return result;
}

function trimText(value: string | null | undefined) {
  return value?.trim() ?? "";
}

function resolveComposeConfigPath(path: string, workingDir: string) {
  if (!path || isAbsolutePath(path) || !workingDir) {
    return path;
  }
  const separator = workingDir.includes("\\") ? "\\" : "/";
  return `${workingDir.replace(/[\\/]+$/g, "")}${separator}${path.replace(
    /^[\\/]+/g,
    "",
  )}`;
}

function isAbsolutePath(path: string) {
  return (
    path.startsWith("/") ||
    path.startsWith("\\\\") ||
    /^[A-Za-z]:[\\/]/.test(path)
  );
}

import { describe, expect, it } from "vitest";
import {
  dockerContainerTarget,
  dockerContainerTargetCapabilities,
} from "../../../lib/targetModel";
import {
  buildHostContainerDialogViewModel,
  canEnterHostContainer,
  canRunHostContainerLifecycleAction,
  containerComposeService,
  containerProjectName,
  hostContainerLifecycleDialogCopy,
  hostContainerLifecycleDisabledReason,
  hostContainerStatusLabel,
  hostContainerStatusTone,
  type HostContainerMetadata,
} from "./hostContainerDialogModel";

function container(
  input: Partial<HostContainerMetadata> &
    Pick<HostContainerMetadata, "id" | "name">,
): HostContainerMetadata {
  const { id, name, ...overrides } = input;
  const hostId = input.hostId ?? "host-lab";
  const runtime = input.runtime ?? "docker";
  const target = dockerContainerTarget({
    containerId: id,
    containerName: name,
    hostId,
    runtime,
  });

  return {
    ...overrides,
    capabilities: dockerContainerTargetCapabilities,
    hostId,
    id,
    image: input.image ?? "kerminal/api:latest",
    name,
    ports: input.ports ?? [],
    runtime,
    shortId: input.shortId ?? id.slice(0, 12),
    state: input.state ?? input.status ?? "running",
    status: input.status ?? "running",
    statusText: input.statusText ?? "Up 12 minutes",
    target,
  };
}

describe("hostContainerDialogModel", () => {
  it("groups compose containers ahead of standalone containers", () => {
    const viewModel = buildHostContainerDialogViewModel(
      [
        container({ id: "standalone1111", name: "redis" }),
        container({
          id: "api1111111111",
          labels: {
            "com.docker.compose.project": "kerminal",
            "com.docker.compose.service": "api",
          },
          name: "api",
        }),
        container({
          id: "worker111111",
          labels: {
            "com.docker.compose.project": "kerminal",
            "com.docker.compose.service": "worker",
          },
          name: "worker",
          status: "exited",
          statusText: "Exited (0) 1 hour ago",
        }),
      ],
      { groupMode: "compose", query: "" },
    );

    expect(viewModel.totalCount).toBe(3);
    expect(viewModel.runningCount).toBe(2);
    expect(viewModel.groups.map((group) => group.title)).toEqual([
      "kerminal",
      "独立容器",
    ]);
    expect(viewModel.groups[0]!.runningCount).toBe(1);
    expect(containerProjectName(viewModel.groups[0]!.containers[0]!)).toBe(
      "kerminal",
    );
    expect(containerComposeService(viewModel.groups[0]!.containers[0]!)).toBe(
      "api",
    );
  });

  it("bridges typed compose metadata and searches config paths", () => {
    const viewModel = buildHostContainerDialogViewModel(
      [
        container({
          compose: {
            configPaths: ["/srv/kerminal/compose.prod.yaml"],
            project: "kerminal",
            service: "api",
            workingDir: "/srv/kerminal",
          },
          id: "api1111111111",
          name: "api",
        }),
        container({ id: "redis1111111", name: "redis" }),
      ],
      { groupMode: "compose", query: "compose.prod.yaml" },
    );

    expect(viewModel.containers.map((item) => item.name)).toEqual(["api"]);
    expect(containerProjectName(viewModel.containers[0]!)).toBe("kerminal");
    expect(containerComposeService(viewModel.containers[0]!)).toBe("api");
  });

  it("filters by container metadata and reports empty search", () => {
    const viewModel = buildHostContainerDialogViewModel(
      [
        container({
          id: "api1111111111",
          name: "api",
          ports: ["8080->80/tcp"],
        }),
        container({ id: "db11111111111", image: "postgres:16", name: "db" }),
      ],
      { groupMode: "flat", query: "postgres" },
    );

    expect(viewModel.containers.map((item) => item.name)).toEqual(["db"]);
    expect(viewModel.emptySearch).toBe(false);

    const emptyViewModel = buildHostContainerDialogViewModel(
      viewModel.containers,
      { groupMode: "flat", query: "no-match" },
    );
    expect(emptyViewModel.emptySearch).toBe(true);
  });

  it("builds status groups and action affordances", () => {
    const running = container({ id: "api1111111111", name: "api" });
    const paused = container({
      id: "jobs11111111",
      name: "jobs",
      status: "paused",
      statusText: "Paused",
    });
    const dead = container({
      id: "bad111111111",
      name: "bad",
      status: "dead",
      statusText: "Dead",
    });
    const viewModel = buildHostContainerDialogViewModel(
      [dead, paused, running],
      { groupMode: "status", query: "" },
      paused.id,
    );

    expect(viewModel.selectedContainer?.name).toBe("jobs");
    expect(viewModel.groups.map((group) => group.title)).toEqual([
      "运行中",
      "已暂停",
      "异常",
    ]);
    expect(hostContainerStatusLabel("restarting")).toBe("重启中");
    expect(hostContainerStatusTone("running")).toBe("running");
    expect(hostContainerStatusTone("paused")).toBe("attention");
    expect(hostContainerStatusTone("dead")).toBe("danger");
    expect(canEnterHostContainer(running)).toBe(true);
    expect(canEnterHostContainer(paused)).toBe(false);
  });

  it("derives lifecycle action availability and confirmation copy", () => {
    const running = container({ id: "api1111111111", name: "api" });
    const stopped = container({
      id: "db11111111111",
      name: "db",
      status: "exited",
      statusText: "Exited",
    });

    expect(canRunHostContainerLifecycleAction(stopped, "start")).toBe(true);
    expect(canRunHostContainerLifecycleAction(running, "start")).toBe(false);
    expect(canRunHostContainerLifecycleAction(running, "stop")).toBe(true);
    expect(canRunHostContainerLifecycleAction(stopped, "stop")).toBe(false);
    expect(canRunHostContainerLifecycleAction(running, "restart")).toBe(true);
    expect(canRunHostContainerLifecycleAction(running, "remove")).toBe(false);
    expect(canRunHostContainerLifecycleAction(stopped, "remove")).toBe(true);
    expect(hostContainerLifecycleDisabledReason(running, "remove")).toBe(
      "先停止容器再删除",
    );
    expect(hostContainerLifecycleDialogCopy("remove", stopped)).toMatchObject({
      confirmLabel: "删除容器",
      inputLabel: "容器名",
      variant: "danger",
    });
  });
});

/**
 * Host-scoped Docker container dialog view model.
 *
 * @author kongweiguang
 */

import type {
  DockerContainerStatus,
  DockerContainerSummary,
} from "../../../lib/dockerApi";
import {
  readContainerComposeConfigPaths,
  readContainerComposeProject,
  readContainerComposeService,
  type ComposeAwareContainerSummary,
} from "./composeProjectModel";

export type HostContainerGroupMode = "compose" | "status" | "flat";
export type HostContainerLifecycleAction =
  | "start"
  | "stop"
  | "restart"
  | "remove";
export type HostContainerInspectorTab = "details" | "stats";

export type HostContainerMetadata = ComposeAwareContainerSummary;

export interface HostContainerDialogViewOptions {
  groupMode: HostContainerGroupMode;
  query: string;
}

export interface HostContainerGroupView {
  id: string;
  containers: HostContainerMetadata[];
  runningCount: number;
  title: string;
  totalCount: number;
}

export interface HostContainerDialogViewModel {
  containers: HostContainerMetadata[];
  emptySearch: boolean;
  groups: HostContainerGroupView[];
  runningCount: number;
  selectedContainer?: HostContainerMetadata;
  stoppedCount: number;
  totalCount: number;
}

export interface HostContainerLifecycleDialogCopy {
  confirmLabel: string;
  description: string;
  helperText: string;
  inputLabel?: string;
  placeholder?: string;
  title: string;
  variant: "danger" | "primary";
}

const statusSortOrder: Record<DockerContainerStatus, number> = {
  running: 0,
  restarting: 1,
  paused: 2,
  created: 3,
  exited: 4,
  dead: 5,
  unknown: 6,
};

const statusLabels: Record<DockerContainerStatus, string> = {
  created: "已创建",
  dead: "异常",
  exited: "已停止",
  paused: "已暂停",
  restarting: "重启中",
  running: "运行中",
  unknown: "未知",
};

export function buildHostContainerDialogViewModel(
  containers: DockerContainerSummary[],
  options: HostContainerDialogViewOptions,
  selectedContainerId?: string,
): HostContainerDialogViewModel {
  const normalizedQuery = normalizeSearch(options.query);
  const source = containers.map(
    (container) => container as HostContainerMetadata,
  );
  const filtered = sortHostContainers(
    normalizedQuery
      ? source.filter((container) =>
          containerMatchesQuery(container, normalizedQuery),
        )
      : source,
  );
  const groups = buildGroups(filtered, options.groupMode);
  const selectedContainer =
    filtered.find((container) => container.id === selectedContainerId) ??
    filtered[0];

  return {
    containers: filtered,
    emptySearch: source.length > 0 && filtered.length === 0,
    groups,
    runningCount: source.filter((container) => container.status === "running")
      .length,
    selectedContainer,
    stoppedCount: source.filter((container) => container.status !== "running")
      .length,
    totalCount: source.length,
  };
}

export function containerProjectName(container: HostContainerMetadata) {
  return readContainerComposeProject(container);
}

export function containerComposeService(container: HostContainerMetadata) {
  return readContainerComposeService(container);
}

export function hostContainerStatusLabel(status: DockerContainerStatus) {
  return statusLabels[status] ?? statusLabels.unknown;
}

export function hostContainerStatusTone(status: DockerContainerStatus) {
  if (status === "running") {
    return "running";
  }
  if (status === "paused" || status === "restarting" || status === "created") {
    return "attention";
  }
  if (status === "dead") {
    return "danger";
  }
  return "muted";
}

export function canEnterHostContainer(container: DockerContainerSummary) {
  return container.status === "running";
}

export function canRunHostContainerLifecycleAction(
  container: DockerContainerSummary,
  action: HostContainerLifecycleAction,
) {
  switch (action) {
    case "start":
      return (
        container.status !== "running" && container.status !== "restarting"
      );
    case "stop":
      return (
        container.status === "running" ||
        container.status === "paused" ||
        container.status === "restarting"
      );
    case "restart":
      return container.status === "running" || container.status === "paused";
    case "remove":
      return (
        container.status !== "running" && container.status !== "restarting"
      );
    default:
      return false;
  }
}

export function hostContainerLifecycleDisabledReason(
  container: DockerContainerSummary,
  action: HostContainerLifecycleAction,
) {
  if (canRunHostContainerLifecycleAction(container, action)) {
    return undefined;
  }
  switch (action) {
    case "start":
      return "容器已在运行或正在重启";
    case "stop":
      return "只有运行中、暂停或重启中的容器可以停止";
    case "restart":
      return "只有运行中或暂停的容器可以重启";
    case "remove":
      return "先停止容器再删除";
    default:
      return "当前状态不可执行";
  }
}

export function hostContainerLifecycleDialogCopy(
  action: HostContainerLifecycleAction,
  container: DockerContainerSummary,
): HostContainerLifecycleDialogCopy {
  switch (action) {
    case "stop":
      return {
        confirmLabel: "停止容器",
        description: `停止 ${container.name} 会中断其中正在运行的进程。`,
        helperText: "停止后可从当前弹框重新启动。",
        title: "停止容器",
        variant: "danger" as const,
      };
    case "restart":
      return {
        confirmLabel: "重启容器",
        description: `重启 ${container.name} 会先停止再启动容器。`,
        helperText: "适合服务卡住或需要重新加载配置时使用。",
        title: "重启容器",
        variant: "primary" as const,
      };
    case "remove":
      return {
        confirmLabel: "删除容器",
        description: `删除 ${container.name} 会移除该容器对象，容器内未持久化数据可能丢失。`,
        helperText: "请输入容器名以确认删除。",
        inputLabel: "容器名",
        placeholder: container.name,
        title: "删除容器",
        variant: "danger" as const,
      };
    case "start":
    default:
      return {
        confirmLabel: "启动容器",
        description: `启动 ${container.name}。`,
        helperText: "启动完成后可以进入容器终端。",
        title: "启动容器",
        variant: "primary" as const,
      };
  }
}

function buildGroups(
  containers: HostContainerMetadata[],
  groupMode: HostContainerGroupMode,
): HostContainerGroupView[] {
  if (groupMode === "flat") {
    return [groupView("all", "全部容器", containers)].filter(
      (group) => group.totalCount > 0,
    );
  }

  const groups = new Map<string, HostContainerMetadata[]>();
  for (const container of containers) {
    const key =
      groupMode === "status"
        ? hostContainerStatusLabel(container.status)
        : containerProjectName(container) || "独立容器";
    groups.set(key, [...(groups.get(key) ?? []), container]);
  }

  return [...groups.entries()]
    .map(([title, groupContainers]) =>
      groupView(groupIdForTitle(groupMode, title), title, groupContainers),
    )
    .sort(compareGroups);
}

function groupView(
  id: string,
  title: string,
  containers: HostContainerMetadata[],
): HostContainerGroupView {
  return {
    containers,
    id,
    runningCount: containers.filter(
      (container) => container.status === "running",
    ).length,
    title,
    totalCount: containers.length,
  };
}

function compareGroups(
  left: HostContainerGroupView,
  right: HostContainerGroupView,
) {
  const leftStandalone = left.title === "独立容器";
  const rightStandalone = right.title === "独立容器";
  if (leftStandalone !== rightStandalone) {
    return leftStandalone ? 1 : -1;
  }
  return (
    right.runningCount - left.runningCount ||
    left.title.localeCompare(right.title)
  );
}

function groupIdForTitle(mode: HostContainerGroupMode, title: string) {
  return `${mode}:${title.toLowerCase().replace(/\s+/g, "-")}`;
}

function sortHostContainers(containers: HostContainerMetadata[]) {
  return [...containers].sort(
    (left, right) =>
      statusSortOrder[left.status] - statusSortOrder[right.status] ||
      containerProjectName(left).localeCompare(containerProjectName(right)) ||
      left.name.localeCompare(right.name),
  );
}

function containerMatchesQuery(
  container: HostContainerMetadata,
  normalizedQuery: string,
) {
  return [
    container.name,
    container.image,
    container.shortId,
    container.id,
    container.statusText,
    container.state,
    container.runtime,
    containerProjectName(container),
    containerComposeService(container),
    ...readContainerComposeConfigPaths(container),
    ...container.ports,
  ]
    .filter(Boolean)
    .join(" ")
    .toLowerCase()
    .includes(normalizedQuery);
}

function normalizeSearch(query: string) {
  return query.trim().toLowerCase();
}
